function ll2v(lat, lng, r) {
  const phi = (90 - lat) * (Math.PI / 180);
  const th  = (lng + 180) * (Math.PI / 180);
  return new THREE.Vector3(
    -r * Math.sin(phi) * Math.cos(th),
     r * Math.cos(phi),
     r * Math.sin(phi) * Math.sin(th)
  );
}

export default function GlobeRed() {
  const mountRef = useRef(null);

  useEffect(() => {
    const mount = mountRef.current;
    if (!mount) return;
    let animId;

    const W = mount.clientWidth  || 500;
    const H = mount.clientHeight || 500;

    const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
    renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
    renderer.setSize(W, H);
    renderer.setClearColor(0x000000, 0);
    mount.appendChild(renderer.domElement);

    const scene  = new THREE.Scene();
    const camera = new THREE.PerspectiveCamera(38, W / H, 0.1, 100);
    camera.position.z = 3.2;

    const group = new THREE.Group();
    scene.add(group);

    // ── Black opaque base sphere (oceans = black) ────────────────────────
    const baseGeo = new THREE.SphereGeometry(0.99, 64, 64);
    const baseMat = new THREE.MeshBasicMaterial({ color: 0x000000 });
    group.add(new THREE.Mesh(baseGeo, baseMat));

    // ── Land dots (only on continents) ───────────────────────────────────
    const dPos = [];
    LAND_DOTS.forEach(([lat, lng]) => {
      const v = ll2v(lat, lng, 1.001);
      dPos.push(v.x, v.y, v.z);
    });
    const dGeo = new THREE.BufferGeometry();
    dGeo.setAttribute("position", new THREE.Float32BufferAttribute(dPos, 3));
    const dMat = new THREE.PointsMaterial({
      color: 0xff2828, size: 0.012, transparent: true, opacity: 0.55, sizeAttenuation: true,
    });
    group.add(new THREE.Points(dGeo, dMat));

    // ── Coastline contour (small bright dots → reads as a line) ──────────
    const cPos = [];
    COAST.forEach(([lat, lng]) => {
      const v = ll2v(lat, lng, 1.005);
      cPos.push(v.x, v.y, v.z);
    });
    const cGeo = new THREE.BufferGeometry();
    cGeo.setAttribute("position", new THREE.Float32BufferAttribute(cPos, 3));
    const cMat = new THREE.PointsMaterial({
      color: 0xff2828, size: 0.010, transparent: true, opacity: 1.0, sizeAttenuation: true,
    });
    group.add(new THREE.Points(cGeo, cMat));

    // Coastline glow (bigger softer halo)
    const cGlowMat = new THREE.PointsMaterial({
      color: 0xff2828, size: 0.020, transparent: true, opacity: 0.25, sizeAttenuation: true,
    });
    group.add(new THREE.Points(cGeo, cGlowMat));

    // ── Crisp rim around globe ───────────────────────────────────────────
    const rimGeo = new THREE.SphereGeometry(1.005, 64, 64);
    const rimMat = new THREE.MeshBasicMaterial({
      color: 0xff2828, transparent: true, opacity: 0.10, side: THREE.BackSide,
    });
    group.add(new THREE.Mesh(rimGeo, rimMat));

    // ── Pins (location markers — same as before) ─────────────────────────
    const C = new THREE.Color(0xff2828);
    const spikes = [];

    LOCATIONS.forEach(([lat, lng, label], i) => {
      const origin = ll2v(lat, lng, 1.005);
      const dir    = origin.clone().normalize();
      const maxH   = 0.09 + ((i * 19 + 7) % 100) / 1000 * 1.6;

      const tipPt  = origin.clone().addScaledVector(dir, maxH);
      const tubGeo = new THREE.TubeGeometry(new THREE.LineCurve3(origin, tipPt), 1, 0.0018, 5, false);
      const tubMat = new THREE.MeshBasicMaterial({ color: C, transparent: true, opacity: 0 });
      const tube   = new THREE.Mesh(tubGeo, tubMat);
      group.add(tube);

      const rGeo = new THREE.RingGeometry(0.013, 0.021, 32);
      const rMat = new THREE.MeshBasicMaterial({ color: C, transparent: true, opacity: 0, side: THREE.DoubleSide });
      const ring = new THREE.Mesh(rGeo, rMat);
      ring.position.copy(origin.clone().addScaledVector(dir, 0.001));
      ring.quaternion.setFromUnitVectors(new THREE.Vector3(0,0,1), dir);
      group.add(ring);

      const dotGeo = new THREE.CircleGeometry(0.007, 32);
      const dotMat = new THREE.MeshBasicMaterial({ color: C, transparent: true, opacity: 0, side: THREE.DoubleSide });
      const dot    = new THREE.Mesh(dotGeo, dotMat);
      dot.position.copy(origin.clone().addScaledVector(dir, 0.002));
      dot.quaternion.setFromUnitVectors(new THREE.Vector3(0,0,1), dir);
      group.add(dot);

      const tGeo = new THREE.SphereGeometry(0.012, 10, 10);
      const tMat = new THREE.MeshBasicMaterial({ color: C, transparent: true, opacity: 0 });
      const tip  = new THREE.Mesh(tGeo, tMat);
      tip.position.copy(tipPt);
      group.add(tip);

      spikes.push({
        tube, ring, dot, tip, origin, dir, maxH,
        delay:   i * 230 + (i * 11 % 280),
        growDur: 900 + (i % 5) * 100,
        holdDur: 3000 + (i % 6) * 500,
        fadeDur: 550,
        phase: "waiting",
        cycleStart: performance.now() + i * 230 + (i * 11 % 280),
        startTime: null,
      });
    });

    const rebuildTube = (tube, origin, dir, maxH, p) => {
      const end = origin.clone().addScaledVector(dir, Math.max(maxH * p, 0.0001));
      const g   = new THREE.TubeGeometry(new THREE.LineCurve3(origin, end), 1, 0.0018, 5, false);
      tube.geometry.dispose();
      tube.geometry = g;
    };

    const easeOut = t => 1 - Math.pow(1-t, 3);
    const easeIn  = t => t * t * t;

    const tick = () => {
      animId = requestAnimationFrame(tick);
      const now = performance.now();
      group.rotation.y += 0.0028;

      spikes.forEach(s => {
        if (s.phase === "waiting" && now >= s.cycleStart) {
          s.phase = "growing"; s.startTime = now;
        }
        if (s.phase === "growing") {
          const t = Math.min((now - s.startTime) / s.growDur, 1);
          const e = easeOut(t);
          rebuildTube(s.tube, s.origin, s.dir, s.maxH, e);
          s.tube.material.opacity  = e * 0.88;
          s.ring.material.opacity  = e * 0.92;
          s.dot.material.opacity   = e;
          s.tip.material.opacity   = 0;
          if (t >= 1) { s.phase = "holding"; s.startTime = now; }
        }
        if (s.phase === "holding") {
          const pulse = 0.4 + 0.5 * Math.sin(now * 0.0028 + s.delay * 0.012);
          s.tip.material.opacity  = pulse;
          s.ring.material.opacity = 0.55 + 0.3 * Math.sin(now * 0.002 + s.delay * 0.009);
          if ((now - s.startTime) >= s.holdDur) { s.phase = "fading"; s.startTime = now; }
        }
        if (s.phase === "fading") {
          const t  = Math.min((now - s.startTime) / s.fadeDur, 1);
          const op = easeIn(1 - t);
          s.tube.material.opacity  = op * 0.88;
          s.ring.material.opacity  = op * 0.92;
          s.dot.material.opacity   = op;
          s.tip.material.opacity   = op * 0.5;
          if (t >= 1) {
            s.phase      = "waiting";
            s.cycleStart = now + 800 + Math.random() * 3500;
            rebuildTube(s.tube, s.origin, s.dir, s.maxH, 0.0001);
            s.tube.material.opacity = 0;
          }
        }
      });

      renderer.render(scene, camera);
    };
    tick();

    const onResize = () => {
      const w = mount.clientWidth, h = mount.clientHeight;
      camera.aspect = w / h;
      camera.updateProjectionMatrix();
      renderer.setSize(w, h);
    };
    window.addEventListener("resize", onResize);

    let drag = false, px = 0, py = 0;
    const onDown = e => { drag = true; px = e.clientX; py = e.clientY; };
    const onMove = e => {
      if (!drag) return;
      group.rotation.y += (e.clientX - px) * 0.004;
      group.rotation.x += (e.clientY - py) * 0.002;
      px = e.clientX; py = e.clientY;
    };
    const onUp = () => (drag = false);
    mount.addEventListener("mousedown", onDown);
    window.addEventListener("mousemove", onMove);
    window.addEventListener("mouseup", onUp);

    return () => {
      cancelAnimationFrame(animId);
      window.removeEventListener("resize", onResize);
      window.removeEventListener("mousemove", onMove);
      window.removeEventListener("mouseup", onUp);
      renderer.dispose();
      if (mount.contains(renderer.domElement)) mount.removeChild(renderer.domElement);
    };
  }, []);

  return (
    <div
      ref={mountRef}
      style={{ width:"100%", height:"100%", minHeight:"500px", background:"transparent", cursor:"grab" }}
    />
  );
}
